#!/bin/bash
# Generated by OrchestKit Claude Plugin
# Created: 2026-05-02

# Integration test: cc-triage.mjs LLM extraction + sentinel + sanitization paths.
# Issue: #1486 (M130 hotfix) — fills the test gap surfaced by /ork:explore audit.
#
# Uses CC_TRIAGE_FIXTURE to substitute claude's stdout, so the test is hermetic
# (no claude CLI required, no network).

set -euo pipefail

SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
PROJECT_ROOT="$(cd "$SCRIPT_DIR/../.." && pwd)"

RED='\033[0;31m'
GREEN='\033[0;32m'
NC='\033[0m'

PASS=0
FAIL=0
log_pass() { echo -e "  ${GREEN}✓${NC} $1"; PASS=$((PASS + 1)); }
log_fail() { echo -e "  ${RED}✗${NC} $1 — $2"; FAIL=$((FAIL + 1)); }

echo "CC Triage Tests (M130 hotfix #1486)"
echo "==================================="

cd "$PROJECT_ROOT"

# Backup and restore mutated state.
GAPS_BACKUP=""
[ -f shared/cc-adoption-gaps.json ] && GAPS_BACKUP=$(cat shared/cc-adoption-gaps.json)
SNAP_BACKUP_DIR=$(mktemp -d)
[ -d shared/cc-snapshots ] && rsync -a shared/cc-snapshots/ "$SNAP_BACKUP_DIR/"

restore() {
  if [ -n "$GAPS_BACKUP" ]; then
    echo "$GAPS_BACKUP" > shared/cc-adoption-gaps.json
  else
    rm -f shared/cc-adoption-gaps.json
  fi
  rm -rf shared/cc-snapshots
  mkdir -p shared/cc-snapshots
  if [ -d "$SNAP_BACKUP_DIR" ] && [ -n "$(ls -A "$SNAP_BACKUP_DIR" 2>&1)" ]; then
    rsync -a "$SNAP_BACKUP_DIR/" shared/cc-snapshots/
  fi
  rm -rf "$SNAP_BACKUP_DIR"
  rm -f /tmp/cc-triage-fixture-*.txt /tmp/cc-triage-out.txt /tmp/cc-triage-gaps.json
}
trap restore EXIT

# Set up minimal fixture: one snapshot file + one matching gap entry.
mkdir -p shared/cc-snapshots
cat > shared/cc-snapshots/2.1.999.md <<'EOF'
# Claude Code 2.1.999

- `claude project purge` removes orphan project metadata
- New `--max-turns` flag on `/agents` command
EOF

write_gaps() {
  cat > shared/cc-adoption-gaps.json <<'EOF'
[
  {
    "version": "2.1.999",
    "parse_failed": false,
    "features": [],
    "raw_bullets_count": 2
  }
]
EOF
}

# ============================================================================
# Test 1: missing OAUTH token → exit 0, no-op (preserves gap entries unchanged)
# ============================================================================
write_gaps
# silent: known-noise (unset of an unset var is a no-op, not a real failure)
unset CLAUDE_CODE_OAUTH_TOKEN || true
EXIT=0
node scripts/cc-triage.mjs > /tmp/cc-triage-out.txt 2>&1 || EXIT=$?
if [ "$EXIT" = "0" ]; then
  log_pass "Missing OAUTH token: exit 0 (graceful no-op)"
else
  log_fail "Missing OAUTH token" "expected exit 0, got $EXIT"
fi

if grep -qF "skipping LLM extraction" /tmp/cc-triage-out.txt; then
  log_pass "Missing OAUTH token: explicit skip message logged"
else
  log_fail "Missing OAUTH skip message" "no 'skipping LLM extraction' in stdout"
fi

UNCHANGED=$(jq '.[0].features | length' shared/cc-adoption-gaps.json)
if [ "$UNCHANGED" = "0" ]; then
  log_pass "Missing OAUTH token: gaps file unchanged (features still empty)"
else
  log_fail "Gaps mutation on no-op" "features became length=$UNCHANGED"
fi

# ============================================================================
# Test 2: malformed JSON from claude → sentinel write (parse_failed: true)
# ============================================================================
write_gaps
FIXTURE=/tmp/cc-triage-fixture-malformed.txt
echo 'this is { not valid json [[[ ' > "$FIXTURE"

EXIT=0
CLAUDE_CODE_OAUTH_TOKEN=fake-token \
CC_TRIAGE_FIXTURE="$FIXTURE" \
  node scripts/cc-triage.mjs > /tmp/cc-triage-out.txt 2>&1 || EXIT=$?

if [ "$EXIT" = "0" ]; then
  log_pass "Malformed JSON: script exits 0 (degrades gracefully)"
else
  log_fail "Malformed JSON exit code" "expected 0, got $EXIT (script crashed instead of writing sentinel)"
fi

PARSE_FAILED=$(jq -r '.[0].parse_failed' shared/cc-adoption-gaps.json)
if [ "$PARSE_FAILED" = "true" ]; then
  log_pass "Malformed JSON: parse_failed sentinel written"
else
  log_fail "parse_failed sentinel" "expected true, got '$PARSE_FAILED'"
fi

FAILED_AT=$(jq -r '.[0].failed_at // empty' shared/cc-adoption-gaps.json)
if [ -n "$FAILED_AT" ]; then
  log_pass "Malformed JSON: failed_at timestamp recorded"
else
  log_fail "failed_at timestamp" "missing on sentinel entry"
fi

# Two attempts logged before sentinel? (callClaude retries once.)
# silent: known-noise (grep -c returns 1 when zero matches; we test the count value below)
ATTEMPT_COUNT=$(grep -c "attempt .* failed" /tmp/cc-triage-out.txt || true)
if [ "$ATTEMPT_COUNT" = "2" ]; then
  log_pass "Malformed JSON: both attempts ran (retry budget honored)"
else
  log_fail "Retry attempts" "expected 2 attempt-failure logs, got $ATTEMPT_COUNT"
fi

# ============================================================================
# Test 3: valid JSON from claude → features populated, scores normalized
# ============================================================================
write_gaps
FIXTURE=/tmp/cc-triage-fixture-ok.txt
cat > "$FIXTURE" <<'EOF'
[
  {"feature_slug": "claude_project_purge", "category": "new_command", "description": "Remove orphan project metadata via CLI", "gap_score": 999, "affected_skills": ["ork:doctor"], "reference_changelog_line": "claude project purge removes orphan project metadata"},
  {"feature_slug": "agents_max_turns", "category": "new_attr", "description": "Bound /agents to N turns", "gap_score": 0, "affected_skills": [], "reference_changelog_line": "New --max-turns flag on /agents"}
]
EOF

CLAUDE_CODE_OAUTH_TOKEN=fake-token \
CC_TRIAGE_FIXTURE="$FIXTURE" \
  node scripts/cc-triage.mjs > /tmp/cc-triage-out.txt 2>&1

FEATURE_COUNT=$(jq '.[0].features | length' shared/cc-adoption-gaps.json)
if [ "$FEATURE_COUNT" = "2" ]; then
  log_pass "Valid JSON: 2 features extracted into gaps entry"
else
  log_fail "Feature count" "expected 2, got $FEATURE_COUNT"
fi

# gap_score must be normalized (model can't drift it past category weight).
PURGE_SCORE=$(jq -r '.[0].features[] | select(.feature_slug=="claude_project_purge") | .gap_score' shared/cc-adoption-gaps.json)
if [ "$PURGE_SCORE" = "15" ]; then
  log_pass "Valid JSON: gap_score normalized to category weight (new_command=15, model said 999)"
else
  log_fail "gap_score normalization" "expected 15 (new_command), got $PURGE_SCORE"
fi

# ============================================================================
# Test 4: feature_slug sanitization — drops injection chars
# ============================================================================
write_gaps
FIXTURE=/tmp/cc-triage-fixture-injection.txt
cat > "$FIXTURE" <<'EOF'
[
  {"feature_slug": "x\" OR label:foo", "category": "new_event", "description": "should be sanitized", "gap_score": 10, "affected_skills": [], "reference_changelog_line": "test"},
  {"feature_slug": "../etc/passwd", "category": "new_event", "description": "should be sanitized", "gap_score": 10, "affected_skills": [], "reference_changelog_line": "test"}
]
EOF

CLAUDE_CODE_OAUTH_TOKEN=fake-token \
CC_TRIAGE_FIXTURE="$FIXTURE" \
  node scripts/cc-triage.mjs > /tmp/cc-triage-out.txt 2>&1

# Both inputs should produce only `[a-z0-9_]` slugs.
SLUGS=$(jq -r '.[0].features[].feature_slug' shared/cc-adoption-gaps.json | tr '\n' ' ')
if echo "$SLUGS" | grep -qE '^[a-z0-9_ ]+$'; then
  log_pass "Slug sanitization: only [a-z0-9_] chars in output ('$SLUGS')"
else
  log_fail "Slug sanitization" "leaked unsafe chars: '$SLUGS'"
fi

# ============================================================================
# Test 5: parse_failed sentinel preserved — no retry on subsequent runs
# ============================================================================
# Manually set parse_failed and re-run with a valid fixture; entry must remain
# untouched (no retry of failed entries).
cat > shared/cc-adoption-gaps.json <<'EOF'
[
  {
    "version": "2.1.999",
    "parse_failed": true,
    "failed_at": "2026-05-02T00:00:00.000Z",
    "features": [],
    "raw_bullets_count": 2
  }
]
EOF

FIXTURE=/tmp/cc-triage-fixture-ok.txt
CLAUDE_CODE_OAUTH_TOKEN=fake-token \
CC_TRIAGE_FIXTURE="$FIXTURE" \
  node scripts/cc-triage.mjs > /tmp/cc-triage-out.txt 2>&1

POST_PARSE_FAILED=$(jq -r '.[0].parse_failed' shared/cc-adoption-gaps.json)
POST_FEATURE_COUNT=$(jq '.[0].features | length' shared/cc-adoption-gaps.json)
if [ "$POST_PARSE_FAILED" = "true" ] && [ "$POST_FEATURE_COUNT" = "0" ]; then
  log_pass "parse_failed sentinel preserved: no retry of permanently-failed entries"
else
  log_fail "Sentinel persistence" "parse_failed=$POST_PARSE_FAILED, features=$POST_FEATURE_COUNT (expected true, 0)"
fi

# ============================================================================
# Test 6: --retry-failed flag re-processes parse_failed entries
# Recovery path for stuck sentinels (e.g. CC 2.1.126 double-dash bug).
# ============================================================================
cat > shared/cc-adoption-gaps.json <<'EOF'
[
  {
    "version": "2.1.999",
    "parse_failed": true,
    "failed_at": "2026-05-02T00:00:00.000Z",
    "features": [],
    "raw_bullets_count": 2
  }
]
EOF

FIXTURE=/tmp/cc-triage-fixture-ok.txt
CLAUDE_CODE_OAUTH_TOKEN=fake-token \
CC_TRIAGE_FIXTURE="$FIXTURE" \
  node scripts/cc-triage.mjs --retry-failed > /tmp/cc-triage-out.txt 2>&1

POST_FAILED=$(jq -r '.[0].parse_failed // "absent"' shared/cc-adoption-gaps.json)
POST_COUNT=$(jq '.[0].features | length' shared/cc-adoption-gaps.json)
if [ "$POST_FAILED" = "absent" ] && [ "$POST_COUNT" = "2" ]; then
  log_pass "--retry-failed: sentinel cleared and features re-extracted ($POST_COUNT features)"
else
  log_fail "--retry-failed" "parse_failed=$POST_FAILED, features=$POST_COUNT (expected absent, 2)"
fi

if grep -qF "clearing sentinel on 2.1.999 for retry" /tmp/cc-triage-out.txt; then
  log_pass "--retry-failed: explicit retry log emitted"
else
  log_fail "--retry-failed log" "expected 'clearing sentinel on 2.1.999 for retry'"
fi

# Same recovery via RETRY_FAILED=1 env var (cron-friendly).
cat > shared/cc-adoption-gaps.json <<'EOF'
[
  {
    "version": "2.1.999",
    "parse_failed": true,
    "failed_at": "2026-05-02T00:00:00.000Z",
    "features": [],
    "raw_bullets_count": 2
  }
]
EOF

CLAUDE_CODE_OAUTH_TOKEN=fake-token \
CC_TRIAGE_FIXTURE="$FIXTURE" \
RETRY_FAILED=1 \
  node scripts/cc-triage.mjs > /tmp/cc-triage-out.txt 2>&1

ENV_POST_COUNT=$(jq '.[0].features | length' shared/cc-adoption-gaps.json)
if [ "$ENV_POST_COUNT" = "2" ]; then
  log_pass "RETRY_FAILED=1 env: sentinel re-attempted same as --retry-failed"
else
  log_fail "RETRY_FAILED env" "features=$ENV_POST_COUNT (expected 2)"
fi

# ============================================================================
# Test 7: W1d (#1696) — empty array result triggers retry + parse_failed
# Root cause of M134 stuck state: model returned `[]` for a non-empty
# changelog, which was syntactically valid JSON so parse_failed stayed false
# and features stayed empty forever. The fix: empty arrays trigger retry,
# and on second empty result, set parse_failed: true.
# ============================================================================
write_gaps
FIXTURE=tests/fixtures/cc-changelogs/triage-empty-result.txt

EXIT=0
CLAUDE_CODE_OAUTH_TOKEN=fake-token \
CC_TRIAGE_FIXTURE="$FIXTURE" \
  node scripts/cc-triage.mjs > /tmp/cc-triage-out.txt 2>&1 || EXIT=$?

if [ "$EXIT" = "0" ]; then
  log_pass "W1d: empty-array fixture exits 0 (degrades gracefully)"
else
  log_fail "W1d empty-array exit" "expected 0, got $EXIT"
fi

PARSE_FAILED=$(jq -r '.[0].parse_failed' shared/cc-adoption-gaps.json)
if [ "$PARSE_FAILED" = "true" ]; then
  log_pass "W1d: empty-array result writes parse_failed sentinel"
else
  log_fail "W1d parse_failed on empty" "expected true, got '$PARSE_FAILED' (this is the M134 root cause)"
fi

if grep -qF "empty array result" /tmp/cc-triage-out.txt; then
  log_pass "W1d: empty-array detection logged with explicit reason"
else
  log_fail "W1d log message" "expected 'empty array result' in stderr (cat /tmp/cc-triage-out.txt)"
fi

if grep -qF "retry firing" /tmp/cc-triage-out.txt; then
  log_pass "W1d: retry-warning emitted on stderr (visible in CI logs)"
else
  log_fail "W1d retry log" "expected 'retry firing' warning before second attempt"
fi

# ============================================================================
# Test 8: empty gaps file → exit 0, no-op
# ============================================================================
echo '[]' > shared/cc-adoption-gaps.json
EXIT=0
CLAUDE_CODE_OAUTH_TOKEN=fake-token \
  node scripts/cc-triage.mjs > /tmp/cc-triage-out.txt 2>&1 || EXIT=$?
if [ "$EXIT" = "0" ] && grep -q "gaps file empty" /tmp/cc-triage-out.txt; then
  log_pass "Empty gaps: exit 0 with explicit message"
else
  log_fail "Empty gaps" "expected exit 0 + 'gaps file empty', got exit=$EXIT"
fi

echo ""
echo "==================================="
echo "  Results: $PASS passed, $FAIL failed"
echo "==================================="

if [[ $FAIL -gt 0 ]]; then
  echo -e "${RED}FAIL${NC}"
  exit 1
fi
echo -e "${GREEN}SUCCESS${NC}"
